INSERT INTO `knowledge_doc` (
  `doc_uuid`, `tenant_id`, `doc_type`, `doc_category`, `priority`, `title`, `summary`,
  `language`, `source_type`, `raw_content`, `char_count`, `status`, `published_at`
) VALUES
  ('demo-fashion-shipping',1001,'SHIPPING_POLICY','shipping',10,'Northstar shipping policy','International shipping timelines and carrier rules.','en','MANUAL','Orders ship in 1-2 business days. US delivery usually takes 3-5 business days. EU delivery usually takes 5-9 business days. Customs delays can add 2-5 days.',180,1,NOW()),
  ('demo-fashion-refund',1001,'REFUND_POLICY','returns',10,'Northstar return policy','Return window and refund rules.','en','MANUAL','Most apparel and accessories can be returned within 30 days of delivery if unused and with tags attached. Final sale items and used socks cannot be returned. Refunds are reviewed by a human agent.',220,1,NOW()),
  ('demo-fashion-sizing',1001,'PRODUCT_GUIDE','sizing',8,'Northstar sizing guide','How customers should choose sizes.','en','MANUAL','Rain jackets fit true to size. Travel pants are slim fit; size up if between sizes. Backpack dimensions comply with most carry-on requirements.',170,1,NOW()),
  ('demo-electro-warranty',1002,'REFUND_POLICY','warranty',10,'VoltLane warranty and returns','Electronics return and warranty rules.','en','MANUAL','Electronics can be returned within 14 days if undamaged and complete. Warranty claims require serial number verification. Refunds and replacements require human approval.',210,1,NOW()),
  ('demo-electro-shipping',1002,'SHIPPING_POLICY','shipping',10,'VoltLane shipping policy','International delivery and battery shipping notes.','en','MANUAL','Most electronics ship within 1 business day. Power banks and batteries may require carrier-specific handling and can take 2 extra days for customs.',190,1,NOW())
ON DUPLICATE KEY UPDATE
  `raw_content` = VALUES(`raw_content`),
  `status` = VALUES(`status`);

